import { jest } from '@jest/globals';
import {
  createReadFileHandler,
  createWriteFileHandler,
  createListDirectoryHandler,
  createSearchCodeHandler,
  createReplaceInFileHandler,
  createCreateDirectoryHandler,
  createCreateMultipleFilesHandler,
  createExecuteCommandHandler
} from '../src/tools/handlers/index.js';

describe('Tool Handlers', () => {
  describe('readFile handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        readFile: jest.fn(),
        getStats: jest.fn(),
        isBinary: jest.fn()
      };
      handler = createReadFileHandler(mockFileSystemManager);
    });

    it('should read a text file successfully', async () => {
      mockFileSystemManager.isBinary.mockResolvedValue(false);
      mockFileSystemManager.readFile.mockResolvedValue('file content');
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 100,
        modified: new Date()
      });

      const result = await handler({ path: 'test.txt' });

      expect(result.content).toBe('file content');
      expect(result.isBinary).toBe(false);
      expect(result.size).toBe(100);
    });

    it('should handle binary files', async () => {
      mockFileSystemManager.isBinary.mockResolvedValue(true);

      const result = await handler({ path: 'image.png' });

      expect(result.content).toBe('[Binary file - content not displayed]');
      expect(result.isBinary).toBe(true);
    });

    it('should throw error if path is missing', async () => {
      await expect(handler({})).rejects.toThrow('Path parameter is required');
    });

    it('should handle read errors', async () => {
      mockFileSystemManager.readFile.mockRejectedValue(new Error('File not found'));

      await expect(handler({ path: 'missing.txt' })).rejects.toThrow('Failed to read file');
    });
  });

  describe('writeFile handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        writeFile: jest.fn(),
        getStats: jest.fn()
      };
      handler = createWriteFileHandler(mockFileSystemManager);
    });

    it('should write file successfully', async () => {
      mockFileSystemManager.writeFile.mockResolvedValue();
      mockFileSystemManager.getStats.mockResolvedValue({
        size: 11
      });

      const result = await handler({ path: 'test.txt', content: 'new content' });

      expect(result.success).toBe(true);
      expect(result.path).toBe('test.txt');
      expect(result.size).toBe(11);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledWith('test.txt', 'new content');
    });

    it('should throw error if path is missing', async () => {
      await expect(handler({ content: 'test' })).rejects.toThrow('Path parameter is required');
    });

    it('should throw error if content is missing', async () => {
      await expect(handler({ path: 'test.txt' })).rejects.toThrow('Content parameter is required');
    });

    it('should handle write errors', async () => {
      mockFileSystemManager.writeFile.mockRejectedValue(new Error('Permission denied'));

      await expect(handler({ path: 'test.txt', content: 'test' }))
        .rejects.toThrow('Failed to write file');
    });
  });

  describe('listDirectory handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        listDirectory: jest.fn()
      };
      handler = createListDirectoryHandler(mockFileSystemManager);
    });

    it('should list directory contents', async () => {
      mockFileSystemManager.listDirectory.mockResolvedValue([
        { name: 'file1.txt', path: 'file1.txt', isFile: true, isDirectory: false },
        { name: 'file2.js', path: 'file2.js', isFile: true, isDirectory: false },
        { name: 'subdir', path: 'subdir', isFile: false, isDirectory: true }
      ]);

      const result = await handler({ path: 'src' });

      expect(result.files).toContain('file1.txt');
      expect(result.directories).toContain('subdir');
    });

    it('should use default path if not provided', async () => {
      mockFileSystemManager.listDirectory.mockResolvedValue([]);

      await handler({});

      expect(mockFileSystemManager.listDirectory).toHaveBeenCalledWith('.', false, true);
    });

    it('should support recursive listing', async () => {
      mockFileSystemManager.listDirectory.mockResolvedValue([]);

      await handler({ path: 'src', recursive: true });

      expect(mockFileSystemManager.listDirectory).toHaveBeenCalledWith('src', true, true);
    });
  });

  describe('searchCode handler', () => {
    let mockSearchEngine;
    let handler;

    beforeEach(() => {
      mockSearchEngine = {
        search: jest.fn(),
        searchRegex: jest.fn(),
        filterByFileType: jest.fn(),
        rankResults: jest.fn()
      };
      handler = createSearchCodeHandler(mockSearchEngine);
    });

    it('should search code successfully', async () => {
      const searchResults = [
        { filePath: 'test.js', lineNumber: 1, line: 'test code', score: 1.0, language: 'javascript' }
      ];
      mockSearchEngine.search.mockResolvedValue(searchResults);
      mockSearchEngine.rankResults.mockReturnValue(searchResults);

      const result = await handler({ query: 'test' });

      expect(result.results).toHaveLength(1);
      expect(result.results[0].file).toBe('test.js');
      expect(mockSearchEngine.search).toHaveBeenCalledWith('test', expect.any(Object));
    });

    it('should support regex search', async () => {
      mockSearchEngine.searchRegex.mockResolvedValue([]);
      mockSearchEngine.rankResults.mockReturnValue([]);

      await handler({ query: 'test.*pattern', regex: true });

      expect(mockSearchEngine.searchRegex).toHaveBeenCalled();
    });

    it('should filter by file type', async () => {
      mockSearchEngine.search.mockResolvedValue([]);
      mockSearchEngine.filterByFileType.mockReturnValue([]);
      mockSearchEngine.rankResults.mockReturnValue([]);

      await handler({ query: 'test', fileType: '.js' });

      expect(mockSearchEngine.filterByFileType).toHaveBeenCalledWith([], ['.js']);
    });

    it('should throw error if query is missing', async () => {
      await expect(handler({})).rejects.toThrow('Query parameter is required');
    });

    it('should limit results to 50', async () => {
      const manyResults = Array(100).fill().map((_, i) => ({
        filePath: `file${i}.js`,
        lineNumber: 1,
        line: 'test',
        score: 1.0,
        language: 'javascript'
      }));
      
      mockSearchEngine.search.mockResolvedValue(manyResults);
      mockSearchEngine.rankResults.mockReturnValue(manyResults);

      const result = await handler({ query: 'test' });

      expect(result.displayedMatches).toBe(50);
      expect(result.totalMatches).toBe(100);
    });
  });

  describe('replaceInFile handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        readFile: jest.fn(),
        writeFile: jest.fn()
      };
      handler = createReplaceInFileHandler(mockFileSystemManager);
    });

    it('should replace text in file', async () => {
      mockFileSystemManager.readFile.mockResolvedValue('hello world hello');

      const result = await handler({
        path: 'test.txt',
        search: 'hello',
        replace: 'hi'
      });

      expect(result.success).toBe(true);
      expect(result.replacementCount).toBe(2);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledWith('test.txt', 'hi world hi');
    });

    it('should return failure if no matches found', async () => {
      mockFileSystemManager.readFile.mockResolvedValue('hello world');

      const result = await handler({
        path: 'test.txt',
        search: 'goodbye',
        replace: 'hi'
      });

      expect(result.success).toBe(false);
      expect(result.replacementCount).toBe(0);
    });

    it('should throw error if parameters are missing', async () => {
      await expect(handler({ path: 'test.txt' }))
        .rejects.toThrow('Search parameter is required');

      await expect(handler({ path: 'test.txt', search: 'test' }))
        .rejects.toThrow('Replace parameter is required');
    });
  });

  describe('createDirectory handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        createDirectory: jest.fn(),
        exists: jest.fn()
      };
      handler = createCreateDirectoryHandler(mockFileSystemManager);
    });

    it('should throw error if path is missing', async () => {
      await expect(handler({})).rejects.toThrow('Path parameter is required');
    });

    // Note: Full integration test would require actual fs operations
    // This is tested in integration tests
  });

  describe('createMultipleFiles handler', () => {
    let mockFileSystemManager;
    let handler;

    beforeEach(() => {
      mockFileSystemManager = {
        writeFile: jest.fn(),
        createDirectory: jest.fn()
      };
      handler = createCreateMultipleFilesHandler(mockFileSystemManager);
    });

    it('should create multiple files successfully', async () => {
      const files = [
        { path: 'file1.txt', content: 'content1' },
        { path: 'file2.txt', content: 'content2' }
      ];

      const result = await handler({ files });

      expect(result.success).toBe(true);
      expect(result.successCount).toBe(2);
      expect(result.errorCount).toBe(0);
      expect(mockFileSystemManager.writeFile).toHaveBeenCalledTimes(2);
    });

    it('should handle partial failures', async () => {
      const files = [
        { path: 'file1.txt', content: 'content1' },
        { path: 'file2.txt', content: 'content2' }
      ];

      mockFileSystemManager.writeFile
        .mockResolvedValueOnce()
        .mockRejectedValueOnce(new Error('Write failed'));

      const result = await handler({ files, rollbackOnError: false });

      expect(result.success).toBe(false);
      expect(result.successCount).toBe(1);
      expect(result.errorCount).toBe(1);
    });

    it('should throw error if files is not an array', async () => {
      await expect(handler({ files: 'not-array' }))
        .rejects.toThrow('Files parameter must be an array');
    });

    it('should throw error if files array is empty', async () => {
      await expect(handler({ files: [] }))
        .rejects.toThrow('Files array cannot be empty');
    });

    it('should handle files with missing properties', async () => {
      const files = [
        { path: 'valid.txt', content: 'valid' },
        { path: '', content: 'invalid path' },
        { path: 'missing-content.txt' }
      ];

      const result = await handler({ files, rollbackOnError: false });

      expect(result.successCount).toBe(1);
      expect(result.errorCount).toBe(2);
    });
  });

  describe('executeCommand handler', () => {
    let mockCommandExecutor;
    let handler;

    beforeEach(() => {
      mockCommandExecutor = {
        execute: jest.fn()
      };
      handler = createExecuteCommandHandler(mockCommandExecutor);
    });

    it('should execute command successfully', async () => {
      mockCommandExecutor.execute.mockResolvedValue({
        success: true,
        stdout: 'command output',
        stderr: '',
        exitCode: 0
      });

      const result = await handler({ command: 'ls -la' });

      expect(result.success).toBe(true);
      expect(result.stdout).toBe('command output');
      expect(mockCommandExecutor.execute).toHaveBeenCalledWith('ls -la', {});
    });

    it('should support custom working directory', async () => {
      mockCommandExecutor.execute.mockResolvedValue({
        stdout: '',
        stderr: '',
        exitCode: 0
      });

      await handler({ command: 'ls', cwd: '/custom/dir' });

      expect(mockCommandExecutor.execute).toHaveBeenCalledWith('ls', { cwd: '/custom/dir' });
    });

    it('should throw error if command is missing', async () => {
      await expect(handler({})).rejects.toThrow('Command parameter is required');
    });

    it('should handle command execution errors', async () => {
      mockCommandExecutor.execute.mockRejectedValue(new Error('Command failed'));

      await expect(handler({ command: 'invalid-command' }))
        .rejects.toThrow('Failed to execute command');
    });
  });

  // TODO: Re-enable getProjectTemplate tests once template import issues are resolved
  // The getProjectTemplate handler tests are temporarily disabled due to template system import issues
});